import 'package:flutter_test/flutter_test.dart';
import 'package:navivox/core/channel/navivox_channel.dart';
import 'package:navivox/features/agents/agents_screen_presentation.dart';

const _agents = [
  NavivoxAgent(id: 'def', name: 'Default', status: 'ready'),
  NavivoxAgent(id: 'arch', name: 'Architect', status: 'ready'),
];

const _servers = [
  NavivoxServer(id: 'local', name: 'Local Gormes', status: 'online'),
  NavivoxServer(id: 'office', name: 'Office', status: 'offline'),
];

final _profiles = [
  NavivoxProfileContact(
    serverId: 'office',
    profileId: 'support',
    displayName: 'Support Triage',
    serverLabel: 'office',
    health: NavivoxProfileHealth.needsAuth,
    latestPreview: 'Waiting for token',
    workspaceRootCount: 1,
    attentionBadges: ['auth'],
    micAvailable: false,
  ),
  NavivoxProfileContact(
    serverId: 'local',
    profileId: 'personal',
    displayName: 'Personal',
    serverLabel: 'local',
    health: NavivoxProfileHealth.offline,
    latestPreview: 'Gateway unavailable',
    workspaceRootCount: 0,
    attentionBadges: ['offline'],
    micAvailable: false,
  ),
  NavivoxProfileContact(
    serverId: 'local',
    profileId: 'mineru',
    displayName: 'Mineru Builder',
    serverLabel: 'local',
    health: NavivoxProfileHealth.online,
    latestPreview: 'Ready to work on mineru',
    latestAt: DateTime(2026, 5, 16, 9, 41),
    workspaceRootCount: 2,
    micAvailable: true,
  ),
];

void main() {
  test('prefers the legacy agent list when agents are present', () {
    final presentation = AgentsScreenPresentation.fromState(
      NavivoxChannelState(
        agents: _agents,
        selectedAgentId: 'arch',
        servers: _servers,
        activeServerId: 'local',
        profileContacts: _profiles,
        selectedProfileContactKey: 'local::mineru',
      ),
    );

    expect(presentation.screenTitle, 'Agents');
    expect(presentation.refreshProfilesTooltip, 'Refresh profiles');
    expect(presentation.showAgentList, isTrue);
    expect(presentation.showProfileFallback, isFalse);
    expect(presentation.showEmptyProfileState, isFalse);
    expect(presentation.agents, _agents);
    expect(presentation.selectedAgentId, 'arch');
  });

  test('shows active-server Profile contacts when the agent list is empty', () {
    final presentation = AgentsScreenPresentation.fromState(
      NavivoxChannelState(
        servers: _servers,
        activeServerId: 'local',
        profileContacts: _profiles,
        selectedProfileContactKey: 'local::mineru',
      ),
    );

    expect(presentation.showAgentList, isFalse);
    expect(presentation.showProfileFallback, isTrue);
    expect(presentation.showEmptyProfileState, isFalse);
    expect(presentation.profileServerLabel, 'Local Gormes');
    expect(presentation.profileFallbackTitle, 'Profiles on Local Gormes');
    expect(
      presentation.profileFallbackSubtitle,
      'Loaded from Gormes profile contacts. Select one profile to scope chat, memory, and config.',
    );
    expect(presentation.selectedProfileContactKey, 'local::mineru');
    expect(presentation.profileContacts.map((profile) => profile.displayName), [
      'Mineru Builder',
      'Personal',
    ]);
  });

  test('falls back to the first visible Profile contact server label', () {
    final presentation = AgentsScreenPresentation.fromState(
      NavivoxChannelState(profileContacts: _profiles),
    );

    expect(presentation.profileServerLabel, 'local');
    expect(presentation.profileContacts.map((profile) => profile.displayName), [
      'Mineru Builder',
      'Personal',
      'Support Triage',
    ]);
  });

  test(
    'reports empty Profile contact state when no fallback contact is visible',
    () {
      final presentation = AgentsScreenPresentation.fromState(
        NavivoxChannelState(
          servers: _servers,
          activeServerId: 'office',
          profileContacts: [_profiles.last],
        ),
      );

      expect(presentation.showAgentList, isFalse);
      expect(presentation.showProfileFallback, isFalse);
      expect(presentation.showEmptyProfileState, isTrue);
      expect(presentation.profileServerLabel, 'Office');
      expect(
        presentation.emptyProfilesTitle,
        'No profiles found on this server',
      );
      expect(
        presentation.emptyProfilesSubtitle,
        'Connect to a Gormes server, refresh profiles, or draft a new profile from a seed.',
      );
      expect(presentation.refreshProfilesLabel, 'Refresh profiles');
      expect(presentation.createImportProfileLabel, 'Add profile');
      expect(presentation.createImportProfileSheetTitle, 'Add a profile');
      expect(
        presentation.createImportProfileSheetSubtitle,
        'Create from a natural-language seed through Gormes, or add another gateway that already has profiles.',
      );
      expect(presentation.createFromSeedTitle, 'Create from seed');
      expect(
        presentation.createFromSeedSubtitle,
        'Ask Gormes to draft a profile from natural language.',
      );
      expect(presentation.addGatewayTitle, 'Add gateway');
      expect(
        presentation.addGatewaySubtitle,
        'Register another Gormes gateway and refresh its profile contacts.',
      );
      expect(presentation.profileContacts, isEmpty);
    },
  );
}

import 'package:flutter_test/flutter_test.dart';
import 'package:navivox/core/channel/navivox_channel.dart';
import 'package:navivox/core/protocol/navivox_memory.dart';
import 'package:navivox/features/memory/memory_dashboard_presentation.dart';

void main() {
  const presentation = MemoryDashboardPresentation();

  test('builds overview scope and count presentation with safe fallbacks', () {
    final overview = NavivoxMemoryOverview(
      profileId: 'mineru',
      workspaceId: 'gormes',
      databaseLabel: '~/.gormes/profiles/mineru/memory.db',
      health: NavivoxMemoryHealth.active,
      totalTurns: 120,
      activeMemoryItems: 12,
      observations: 34,
      conclusions: 5,
      sessionSummaries: 7,
      entities: 18,
      relationships: 21,
      lastUpdatedAt: DateTime.utc(2026, 5, 21, 15, 28, 18),
    );
    const contact = NavivoxProfileContact(
      serverId: 'local',
      profileId: 'mineru',
      displayName: ' ',
      serverLabel: ' ',
      health: NavivoxProfileHealth.online,
      latestPreview: 'Ready',
    );

    final model = presentation.overviewFor(overview, activeProfile: contact);

    expect(model.healthLabel, 'Goncho active');
    expect(model.serverLine, 'Server: default');
    expect(model.profileLine, 'Profile: mineru');
    expect(model.workspaceLine, 'Workspace: gormes');
    expect(model.databaseTitle, 'Database');
    expect(model.databaseLabel, '~/.gormes/profiles/mineru/memory.db');
    expect(model.lastUpdatedLine, 'Last updated: 2026-05-21T15:28:18.000Z');
    expect(model.counts.map((count) => '${count.label}:${count.count}'), [
      'Turns:120',
      'Active memory items:12',
      'Observations:34',
      'Conclusions:5',
      'Session summaries:7',
      'Entities:18',
      'Relationships:21',
    ]);
  });

  test('builds search copy and memory item metadata presentation', () {
    expect(presentation.searchTitle, 'Search & Browse');
    expect(presentation.searchFieldLabel, 'Search memories');
    expect(
      presentation.searchUnavailableMessage,
      'Gormes memory search API is unavailable.',
    );
    expect(presentation.emptySearchMessage, 'No memories found.');

    const item = NavivoxMemoryItem(
      id: 'mem-1',
      type: NavivoxMemoryType.memoryItems,
      snippet: 'Mineru uses Goncho memory for workspace recall.',
      sessionId: 's-1',
      peerId: 'mineru',
      status: 'current',
      tags: ['workspace', 'recall'],
    );

    final card = presentation.itemFor(item);

    expect(card.keyValue, 'memory-item-memory_items-mem-1');
    expect(card.title, 'Mineru uses Goncho memory for workspace recall.');
    expect(card.metadataLine, 'memory_items · current · s-1 · mineru');
    expect(card.tags, ['workspace', 'recall']);

    final blank = presentation.itemFor(
      const NavivoxMemoryItem(
        id: 'blank',
        type: NavivoxMemoryType.observations,
        snippet: 'No metadata',
      ),
    );

    expect(blank.metadataLine, 'observations');
  });

  test('builds detail rows and safe management action copy', () {
    const detail = NavivoxMemoryDetail(
      id: 'mem-1',
      type: NavivoxMemoryType.memoryItems,
      content: 'Mineru uses Goncho memory for workspace recall.',
      source: 'goncho_memory_items',
      sessionId: 's-1',
      peerId: 'mineru',
      createdAt: '2026-05-21T15:30:00Z',
      status: 'current',
      provenance: 'derived from reviewed session s-1',
      linkedEntities: ['Mineru'],
      linkedRelationships: ['Mineru RELATED_TO Goncho'],
    );

    final model = presentation.detailFor(detail);

    expect(model.title, 'Memory detail');
    expect(model.content, detail.content);
    expect(model.rows.map((row) => row.line), [
      'Type: memory_items',
      'Source: goncho_memory_items',
      'Session: s-1',
      'Peer: mineru',
      'Status: current',
      'Created: 2026-05-21T15:30:00Z',
    ]);
    expect(model.provenanceTitle, 'Provenance');
    expect(model.linkedEntitiesTitle, 'Linked entities');
    expect(model.linkedRelationshipsTitle, 'Linked relationships');
    expect(model.rawSourcePreservedLabel, 'Raw source preserved');
    expect(
      model.actions.map((action) => '${action.type.wireValue}:${action.label}'),
      [
        'pin:Pin',
        'archive:Archive',
        'mark_stale:Mark stale',
        'add_correction:Add correction',
      ],
    );
    expect(model.actions.last.requiresCorrection, isTrue);
  });

  test('builds degraded, correction, and action feedback copy', () {
    const contact = NavivoxProfileContact(
      serverId: 'local',
      profileId: 'mineru',
      displayName: 'Mineru Builder',
      serverLabel: 'local',
      health: NavivoxProfileHealth.warning,
      latestPreview: 'Memory API unavailable',
    );

    final error = presentation.errorFor(
      contact,
      message: 'Gormes memory API is unavailable.',
    );

    expect(error.title, 'Goncho degraded');
    expect(error.profileLine, 'Profile: Mineru Builder');
    expect(error.message, 'Gormes memory API is unavailable.');
    expect(
      presentation.detailUnavailableMessage,
      'Gormes memory detail API is unavailable.',
    );
    expect(presentation.correctionDialogTitle, 'Add correction');
    expect(presentation.correctionFieldLabel, 'Correction note');
    expect(
      presentation.correctionFieldHelperText,
      'Adds a superseding note; raw source is preserved.',
    );
    expect(presentation.cancelLabel, 'Cancel');
    expect(presentation.saveCorrectionLabel, 'Save correction');

    expect(
      presentation.actionMessageFor(
        const NavivoxMemoryActionResult(
          accepted: true,
          action: NavivoxMemoryActionType.archive,
          message: 'Archive requested.',
        ),
        requestedAction: NavivoxMemoryActionType.archive,
      ),
      'Archive requested.',
    );
    expect(
      presentation.actionMessageFor(
        const NavivoxMemoryActionResult(
          accepted: true,
          action: NavivoxMemoryActionType.pin,
          message: ' ',
        ),
        requestedAction: NavivoxMemoryActionType.pin,
      ),
      'Pin requested.',
    );
    expect(
      presentation.actionMessageFor(
        const NavivoxMemoryActionResult.degraded(
          action: NavivoxMemoryActionType.archive,
          reason: 'Gormes memory action API is unavailable.',
        ),
        requestedAction: NavivoxMemoryActionType.archive,
      ),
      'Gormes memory action API is unavailable.',
    );
  });
}

import 'package:flutter_test/flutter_test.dart';
import 'package:navivox/core/channel/navivox_channel.dart';
import 'package:navivox/features/settings/providers/voice_settings_provider.dart';
import 'package:navivox/features/settings/settings_screen_presentation.dart';
import 'package:navivox/router/app_routes.dart';

void main() {
  const presentation = SettingsScreenPresentation();

  test('centralizes static settings screen copy and management rows', () {
    expect(presentation.title, 'Voice settings');
    expect(presentation.globalTitle, 'Global app settings');
    expect(
      presentation.globalSubtitle,
      'Voice controls stay local to this app. Gateway and profile settings live in their own screens.',
    );

    expect(
      presentation.managementRows.map(
        (row) => '${row.keyValue}:${row.title}:${row.subtitle}:${row.route}',
      ),
      [
        'settings-manage-gateways:Manage gateways:Add, test, edit, and remove Gormes gateway connections.:${AppRoutes.servers}',
        'settings-manage-profiles:Manage profile contacts:Create, refresh, edit, or select profiles from the Agents tab.:${AppRoutes.agents}',
      ],
    );

    expect(presentation.continuousVoiceTitle, 'Continuous voice');
    expect(
      presentation.continuousVoiceSubtitle,
      'Use local device STT for the active profile',
    );
    expect(presentation.commandWordTitle, 'Command word');
    expect(presentation.profileSwitchingTitle, 'Voice profile switching');
    expect(
      presentation.profileSwitchingSubtitle,
      'Allow local command-word profile switches',
    );
  });

  test('builds management summary with singular and plural labels', () {
    expect(
      presentation.managementOverview(serverCount: 1, profileContactCount: 1),
      const SettingsManagementOverviewPresentation(
        keyValue: 'settings-management-overview',
        title: 'Management overview',
        subtitle: '1 Gormes gateway · 1 profile contact',
      ),
    );

    expect(
      presentation.managementOverview(serverCount: 2, profileContactCount: 3),
      const SettingsManagementOverviewPresentation(
        keyValue: 'settings-management-overview',
        title: 'Management overview',
        subtitle: '2 Gormes gateways · 3 profile contacts',
      ),
    );
  });

  test('builds trust row state for the active Gormes gateway', () {
    const server = NavivoxServer(
      id: 'local',
      name: 'Local Gormes',
      status: 'online',
    );

    expect(
      presentation.trustRowFor(server, settings: const NavivoxVoiceSettings()),
      const SettingsTrustRowPresentation(
        keyValue: 'voice-trust-local',
        title: 'Trust Local Gormes for voice',
        subtitle: 'Local-only trust, not server config',
        trusted: false,
      ),
    );

    expect(
      presentation
          .trustRowFor(
            server,
            settings: const NavivoxVoiceSettings(trustedServerIds: {'local'}),
          )
          .trusted,
      isTrue,
    );
  });

  test('builds current session scope rows and health labels', () {
    const server = NavivoxServer(
      id: 'local',
      name: 'Local Gormes',
      status: 'online',
    );
    const profile = NavivoxProfileContact(
      serverId: 'local',
      profileId: 'mineru',
      displayName: 'Mineru Builder',
      serverLabel: 'local',
      health: NavivoxProfileHealth.online,
      latestPreview: 'Ready',
    );

    final scope = presentation.currentScopeFor(
      activeServer: server,
      activeProfile: profile,
    );

    expect(scope, isNotNull);
    expect(scope!.title, 'Current session scope');
    expect(
      scope.subtitle,
      'Local settings apply to the currently selected gateway and profile contact.',
    );
    expect(
      scope.gateway,
      const SettingsScopeRowPresentation(
        keyValue: 'settings-current-gateway',
        title: 'Active Gormes gateway',
        subtitle: 'Local Gormes · local · online',
      ),
    );
    expect(
      scope.profile,
      const SettingsScopeRowPresentation(
        keyValue: 'settings-current-profile',
        title: 'Active profile contact',
        subtitle: 'Mineru Builder · local/mineru · online',
      ),
    );

    expect(
      presentation.currentScopeFor(activeServer: null, activeProfile: null),
      isNull,
    );
    expect(presentation.healthLabel(NavivoxProfileHealth.online), 'online');
    expect(presentation.healthLabel(NavivoxProfileHealth.offline), 'offline');
    expect(presentation.healthLabel(NavivoxProfileHealth.needsAuth), 'auth');
    expect(presentation.healthLabel(NavivoxProfileHealth.warning), 'warning');
  });
}

import 'package:flutter/material.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:navivox/core/channel/navivox_channel.dart';
import 'package:navivox/features/profile_contacts/profile_contact_avatar.dart';

const _profile = NavivoxProfileContact(
  serverId: 'local',
  profileId: 'mineru',
  displayName: 'Mineru Builder',
  serverLabel: 'Local Gormes',
  health: NavivoxProfileHealth.online,
  latestPreview: '',
);

void main() {
  testWidgets('renders a stable Profile contact initial and semantics label', (
    tester,
  ) async {
    final semantics = tester.ensureSemantics();

    await tester.pumpWidget(
      const MaterialApp(
        home: Scaffold(body: ProfileContactAvatar(contact: _profile)),
      ),
    );

    expect(find.text('M'), findsOneWidget);
    expect(
      find.bySemanticsLabel('Mineru Builder profile avatar'),
      findsOneWidget,
    );

    final text = tester.widget<Text>(find.text('M'));
    expect(text.style?.color, Colors.white);

    final avatar = tester.widget<DecoratedBox>(find.byType(DecoratedBox));
    final decoration = avatar.decoration as BoxDecoration;
    final gradient = decoration.gradient as LinearGradient;
    expect(decoration.shape, BoxShape.circle);
    expect(gradient.colors, const [Color(0xffff9500), Color(0xffff2d55)]);
    semantics.dispose();
  });
}

import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:navivox/core/channel/navivox_channel.dart';
import 'package:navivox/core/channel/navivox_channel_provider.dart';
import 'package:navivox/core/gateway/navivox_gateway_protocol.dart';
import 'package:navivox/router/app_router.dart';

import '../../support/test_navivox_channel.dart';

const _servers = [
  NavivoxServer(id: 'local', name: 'Local Gormes', status: 'online'),
];

void main() {
  testWidgets(
    'create from seed drafts editable fields and applies explicit workspace through Gormes',
    (tester) async {
      await tester.binding.setSurfaceSize(const Size(900, 1200));
      addTearDown(() => tester.binding.setSurfaceSize(null));

      final channel = TestNavivoxChannel()
        ..seedServers(_servers, activeServerId: 'local')
        ..seedProfileSeedResults(
          draft: _draftResult(),
          apply: _appliedResult(workspaceCount: 1),
        );

      await tester.pumpWidget(
        ProviderScope(
          overrides: [navivoxChannelProvider.overrideWithValue(channel)],
          child: const _RouterTestApp(),
        ),
      );
      await tester.pumpAndSettle();

      await tester.tap(find.byTooltip('Add profile'));
      await tester.pumpAndSettle();
      await tester.tap(find.byKey(const ValueKey('profile-create-from-seed')));
      await tester.pumpAndSettle();

      await tester.enterText(
        find.byKey(const ValueKey('profile-seed-input')),
        ' work on mineru repo ',
      );
      await tester.tap(find.byKey(const ValueKey('profile-seed-draft-button')));
      await tester.pumpAndSettle();

      _expectProfileSeedCall(
        channel.profileSeedCalls.single,
        seed: 'work on mineru repo',
        apply: false,
        workspaceRoots: const [],
      );
      expect(find.text('generation_source=template'), findsOneWidget);
      expect(
        find.text(
          'Evidence: template_fallback, workspace_confirmation_required',
        ),
        findsOneWidget,
      );
      expect(find.widgetWithText(TextField, 'Profile ID'), findsOneWidget);
      expect(find.widgetWithText(TextField, 'Display name'), findsOneWidget);
      expect(find.widgetWithText(TextField, 'Instructions'), findsOneWidget);
      expect(find.widgetWithText(TextField, 'Provider'), findsOneWidget);
      expect(find.widgetWithText(TextField, 'Model'), findsOneWidget);
      expect(find.widgetWithText(TextField, 'Tool policy'), findsOneWidget);
      expect(find.widgetWithText(TextField, 'Voice metadata'), findsOneWidget);
      expect(find.text('Workspace suggestions'), findsOneWidget);
      expect(find.textContaining('requires confirmation'), findsOneWidget);

      var applyButton = tester.widget<FilledButton>(
        find.byKey(const ValueKey('profile-seed-apply-button')),
      );
      expect(applyButton.onPressed, isNull);

      await tester.scrollUntilVisible(
        find.byKey(const ValueKey('profile-seed-workspace-path')),
        220,
        scrollable: find.byType(Scrollable).last,
      );
      await tester.enterText(
        find.byKey(const ValueKey('profile-seed-workspace-path')),
        '/work/mineru',
      );
      await tester.pumpAndSettle();
      applyButton = tester.widget<FilledButton>(
        find.byKey(const ValueKey('profile-seed-apply-button')),
      );
      expect(applyButton.onPressed, isNotNull);

      await tester.tap(find.byKey(const ValueKey('profile-seed-apply-button')));
      await tester.pumpAndSettle();

      _expectProfileSeedCall(
        channel.profileSeedCalls.last,
        seed: 'work on mineru repo',
        apply: true,
        workspaceRoots: const ['/work/mineru'],
      );
      expect(
        find.byKey(const ValueKey('profile-contact-local-work-mineru-repo')),
        findsOneWidget,
      );

      await tester.tap(
        find.byKey(const ValueKey('profile-contact-local-work-mineru-repo')),
      );
      await tester.pumpAndSettle();

      expect(channel.selectedProfileScope, (
        serverId: 'local',
        profileId: 'work-mineru-repo',
      ));
      expect(find.text('Work Mineru Repo'), findsOneWidget);
    },
  );

  testWidgets(
    'template drafts can be applied after explicit no-workspace confirmation',
    (tester) async {
      await tester.binding.setSurfaceSize(const Size(900, 1200));
      addTearDown(() => tester.binding.setSurfaceSize(null));

      final channel = TestNavivoxChannel()
        ..seedServers(_servers, activeServerId: 'local')
        ..seedProfileSeedResults(
          draft: _draftResult(),
          apply: _appliedResult(workspaceCount: 0),
        );

      await tester.pumpWidget(
        ProviderScope(
          overrides: [navivoxChannelProvider.overrideWithValue(channel)],
          child: const _RouterTestApp(),
        ),
      );
      await tester.pumpAndSettle();

      await tester.tap(find.byTooltip('Add profile'));
      await tester.pumpAndSettle();
      await tester.tap(find.byKey(const ValueKey('profile-create-from-seed')));
      await tester.pumpAndSettle();
      await tester.enterText(
        find.byKey(const ValueKey('profile-seed-input')),
        'work on mineru repo',
      );
      await tester.tap(find.byKey(const ValueKey('profile-seed-draft-button')));
      await tester.pumpAndSettle();

      expect(find.text('Provider status: unconfigured'), findsOneWidget);
      expect(find.text('generation_source=template'), findsOneWidget);

      await tester.scrollUntilVisible(
        find.byKey(const ValueKey('profile-seed-no-workspace-confirmation')),
        220,
        scrollable: find.byType(Scrollable).last,
      );
      await tester.tap(
        find.byKey(const ValueKey('profile-seed-no-workspace-confirmation')),
      );
      await tester.pumpAndSettle();
      await tester.scrollUntilVisible(
        find.byKey(const ValueKey('profile-seed-apply-button')),
        120,
        scrollable: find.byType(Scrollable).last,
      );
      await tester.tap(find.byKey(const ValueKey('profile-seed-apply-button')));
      await tester.pumpAndSettle();

      _expectProfileSeedCall(
        channel.profileSeedCalls.last,
        seed: 'work on mineru repo',
        apply: true,
        workspaceRoots: const [],
      );
      expect(
        find.byKey(const ValueKey('profile-contact-local-work-mineru-repo')),
        findsOneWidget,
      );
    },
  );
}

void _expectProfileSeedCall(
  ({String seed, bool apply, List<String> workspaceRoots}) actual, {
  required String seed,
  required bool apply,
  required List<String> workspaceRoots,
}) {
  expect(actual.seed, seed);
  expect(actual.apply, apply);
  expect(actual.workspaceRoots, workspaceRoots);
}

NavivoxProfileSeedResult _draftResult() {
  return NavivoxProfileSeedResult(
    action: 'profile_seed_draft',
    status: 'draft',
    applied: false,
    profileId: '',
    root: '',
    workspaceCount: 0,
    draft: _draft(),
    contact: const {},
  );
}

NavivoxProfileSeedResult _appliedResult({required int workspaceCount}) {
  return NavivoxProfileSeedResult(
    action: 'profile_seed_applied',
    status: 'applied',
    applied: true,
    profileId: 'work-mineru-repo',
    root: '.../work-mineru-repo',
    workspaceCount: workspaceCount,
    draft: _draft(),
    contact: const {
      'server_id': 'local',
      'profile_id': 'work-mineru-repo',
      'display_name': 'Work Mineru Repo',
      'server_label': 'local',
      'health': 'online',
      'latest_preview': 'Profile ready',
      'latest_preview_kind': 'status',
      'workspace_root_count': 0,
      'workspace_roots_ok': true,
      'attention_badges': <String>[],
      'mic_available': false,
      'active_turn_state': 'idle',
      'avatar_seed': 'local:work-mineru-repo',
    },
  );
}

Map<String, Object?> _draft() {
  return const {
